// --- Cryptographic Utilities ---

async function hashPassword(password, salt) {
  const encoder = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    "raw",
    encoder.encode(password),
    "PBKDF2",
    false,
    ["deriveBits"]
  );

  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: "PBKDF2",
      salt: encoder.encode(salt),
      iterations: 100000,
      hash: "SHA-256",
    },
    keyMaterial,
    256
  );

  return bufferToHex(derivedBits);
}

function bufferToHex(buffer) {
  return [...new Uint8Array(buffer)]
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

async function generateSecureToken() {
  const tokenBytes = new Uint8Array(32);
  crypto.getRandomValues(tokenBytes);
  return bufferToHex(tokenBytes);
}

async function generateSalt() {
  const saltBytes = new Uint8Array(16);
  crypto.getRandomValues(saltBytes);
  return bufferToHex(saltBytes);
}

// Constant-time string comparison to prevent timing attacks
function constantTimeEqual(a, b) {
  if (typeof a !== "string" || typeof b !== "string") {
    return false;
  }
  if (a.length !== b.length) {
    return false;
  }
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

// --- Rate Limiting ---

async function checkRateLimit(env, identifier, maxAttempts = 5, windowSeconds = 300) {
  const key = `ratelimit:${identifier}`;
  const record = await env.SESSIONS.get(key, { type: "json" });

  const now = Date.now();

  if (!record) {
    await env.SESSIONS.put(
      key,
      JSON.stringify({ attempts: 1, firstAttempt: now }),
      { expirationTtl: windowSeconds }
    );
    return { allowed: true, remaining: maxAttempts - 1 };
  }

  if (record.attempts >= maxAttempts) {
    const timeLeft = Math.ceil(
      (record.firstAttempt + windowSeconds * 1000 - now) / 1000
    );
    return { allowed: false, remaining: 0, retryAfter: timeLeft > 0 ? timeLeft : windowSeconds };
  }

  await env.SESSIONS.put(
    key,
    JSON.stringify({ attempts: record.attempts + 1, firstAttempt: record.firstAttempt }),
    { expirationTtl: windowSeconds }
  );

  return { allowed: true, remaining: maxAttempts - record.attempts - 1 };
}

async function resetRateLimit(env, identifier) {
  const key = `ratelimit:${identifier}`;
  await env.SESSIONS.delete(key);
}

